package com.agrios.platform.inventory.application;
import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*;
import com.agrios.platform.farm.domain.*; import com.agrios.platform.inventory.api.InventoryDtos; import com.agrios.platform.inventory.domain.*; import java.math.BigDecimal; import java.util.*; import org.junit.jupiter.api.Test;
class InventoryServiceTest { @Test void rejectsDuplicateItemCode(){var items=mock(InventoryItemRepository.class);var lots=mock(InventoryLotRepository.class);var moves=mock(StockMovementRepository.class);var farms=mock(FarmRepository.class);UUID tenant=UUID.randomUUID(),farm=UUID.randomUUID();when(farms.findByIdAndTenantId(farm,tenant)).thenReturn(Optional.of(mock(FarmEntity.class)));when(items.existsByTenantIdAndFarmIdAndItemCode(tenant,farm,"UREA")).thenReturn(true);var service=new InventoryService(items,lots,moves,farms);assertThrows(RuntimeException.class,()->service.create(tenant,UUID.randomUUID(),new InventoryDtos.CreateItemRequest(farm,"UREA","Urea","FERTILIZER","KG",BigDecimal.TEN)));}}
